```class Solution {
    public long[] unmarkedSumArray(int[] nums, int[][] queries) {
        long[] res = new long[queries.length];
        for (int i = 0; i < queries.length; i++) {
            int index = queries[i][0];
            int k = queries[i][1];
            boolean[] marked = new boolean[nums.length];
            marked[index] = true;
            Arrays.sort(nums);
            int j = 0;
            for (int num : nums) {
                if (!marked[j]) {
                    k--;
                    if (k == 0) break;
                }
                j++;
            }
            long sum = 0;
            for (int j = 0; j < nums.length; j++) {
                if (!marked[j]) {
                    sum += nums[j];
                }
            }
            res[i] = sum;
        }
        return res;
    }
}```
